onClick:
{{
qryValidarClaveAnulacionSA.run(

() => {

    if (qryValidarClaveAnulacionSA.data[0].clave_valida == 0) {

        showAlert(
            "Clave incorrecta.",
            "error"
        );

        return;

    }

    qrySAAnular.run(

        () => {

                        closeModal("mdlAnularSA");

            resetWidget("inpClaveAnularSA");

            qrySAConsultar.run();

            storeValue("saActual", null);

            storeValue("idSAActual", null);

            storeValue("modoSA", "CREACION");

            showAlert(
                "Solicitud de Avance anulada correctamente.",
                "success"
            );

        },

        (error) => {

            showAlert(
                error.message,
                "error"
            );

        }

    );

},

(error) => {

    showAlert(
        error.message,
        "error"
    );

}

)
}}
